<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f4f7fb;
      --card: #ffffff;
      --text: #1d2939;
      --muted: #667085;
      --border: #d9e1ec;
      --accent: #2563eb;
      --danger: #c62828;
      --success: #087443;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      min-height: 100vh;
      background: var(--bg);
      color: var(--text);
      font-family: Arial, Helvetica, sans-serif;
    }

    main {
      width: min(100% - 32px, 900px);
      margin: 32px auto;
    }

    h1, h2 {
      margin: 0 0 16px;
    }

    h1 { font-size: 1.8rem; }
    h2 { font-size: 1.15rem; }

    .card {
      background: var(--card);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 20px;
      margin-bottom: 18px;
      box-shadow: 0 2px 8px rgba(16, 24, 40, 0.04);
    }

    .grid {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 14px;
    }

    .field {
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    label {
      font-size: 0.9rem;
      font-weight: 700;
    }

    input, select, button {
      font: inherit;
      border-radius: 6px;
    }

    input, select {
      width: 100%;
      padding: 10px;
      border: 1px solid var(--border);
      background: #fff;
      color: var(--text);
    }

    button {
      cursor: pointer;
      border: 0;
      padding: 10px 14px;
      font-weight: 700;
    }

    #add-expense {
      width: 100%;
      align-self: end;
      background: var(--accent);
      color: #fff;
    }

    #add-expense:hover { background: #1d4ed8; }

    #form-error {
      min-height: 1.25em;
      margin: 12px 0 0;
      color: var(--danger);
      font-size: 0.92rem;
      font-weight: 700;
    }

    .summary-top {
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 12px;
      margin-bottom: 16px;
    }

    #total {
      color: var(--success);
      font-size: 1.6rem;
      font-weight: 800;
    }

    .category-totals {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 10px;
    }

    .cat-total {
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 10px;
      background: #f9fbff;
      font-size: 0.9rem;
    }

    .cat-total strong {
      display: block;
      margin-top: 4px;
      font-size: 1rem;
    }

    #expense-list {
      display: flex;
      flex-direction: column;
      gap: 10px;
    }

    .expense {
      display: grid;
      grid-template-columns: 1fr 1fr 1fr auto;
      align-items: center;
      gap: 12px;
      padding: 13px;
      border: 1px solid var(--border);
      border-radius: 8px;
      background: #fff;
    }

    .expense .amount {
      font-weight: 800;
      color: var(--success);
    }

    .expense .category {
      text-transform: capitalize;
    }

    .expense .date {
      color: var(--muted);
    }

    .expense .note {
      grid-column: 1 / -1;
      margin-top: -4px;
      color: var(--muted);
      font-size: 0.9rem;
      word-break: break-word;
    }

    .exp-del {
      background: #fee2e2;
      color: #991b1b;
    }

    .exp-del:hover { background: #fecaca; }

    .empty {
      color: var(--muted);
      text-align: center;
      padding: 18px;
    }

    @media (max-width: 680px) {
      main {
        width: min(100% - 20px, 900px);
        margin: 18px auto;
      }

      .grid, .category-totals {
        grid-template-columns: 1fr 1fr;
      }

      .expense {
        grid-template-columns: 1fr 1fr auto;
      }

      .expense .date {
        grid-column: 1 / 3;
      }
    }

    @media (max-width: 420px) {
      .grid, .category-totals {
        grid-template-columns: 1fr;
      }

      .expense {
        grid-template-columns: 1fr auto;
      }

      .expense .category, .expense .date {
        grid-column: 1 / 2;
      }
    }
  </style>
</head>
<body>
  <main>
    <h1>Personal Expense Tracker</h1>

    <section class="card" aria-labelledby="add-heading">
      <h2 id="add-heading">Add Expense</h2>
      <form id="expense-form" novalidate>
        <div class="grid">
          <div class="field">
            <label for="amount">Amount</label>
            <input id="amount" type="number" min="0.01" step="0.01" inputmode="decimal" placeholder="0.00">
          </div>
          <div class="field">
            <label for="category">Category</label>
            <select id="category">
              <option value="groceries">Groceries</option>
              <option value="transport">Transport</option>
              <option value="bills">Bills</option>
              <option value="fun">Fun</option>
            </select>
          </div>
          <div class="field">
            <label for="date">Date</label>
            <input id="date" type="date">
          </div>
          <div class="field">
            <label for="note">Note (optional)</label>
            <input id="note" type="text" maxlength="160" placeholder="What was it for?">
          </div>
        </div>
        <p id="form-error" role="alert" aria-live="polite"></p>
        <button id="add-expense" type="submit">Add Expense</button>
      </form>
    </section>

    <section class="card" aria-labelledby="filter-heading">
      <h2 id="filter-heading">Filters</h2>
      <div class="grid">
        <div class="field">
          <label for="filter-category">Category</label>
          <select id="filter-category">
            <option value="all">All categories</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="field">
          <label for="filter-from">From date</label>
          <input id="filter-from" type="date">
        </div>
        <div class="field">
          <label for="filter-to">To date</label>
          <input id="filter-to" type="date">
        </div>
      </div>
    </section>

    <section class="card" aria-labelledby="summary-heading">
      <div class="summary-top">
        <h2 id="summary-heading">Visible Total</h2>
        <div>$<span id="total">0.00</span></div>
      </div>
      <div class="category-totals">
        <div class="cat-total" data-cat="groceries">Groceries<strong>$0.00</strong></div>
        <div class="cat-total" data-cat="transport">Transport<strong>$0.00</strong></div>
        <div class="cat-total" data-cat="bills">Bills<strong>$0.00</strong></div>
        <div class="cat-total" data-cat="fun">Fun<strong>$0.00</strong></div>
      </div>
    </section>

    <section class="card" aria-labelledby="expenses-heading">
      <h2 id="expenses-heading">Expenses</h2>
      <div id="expense-list" aria-live="polite"></div>
    </section>
  </main>

  <script>
    (function () {
      const STORAGE_KEY = "personal-expense-tracker-expenses";
      const categories = ["groceries", "transport", "bills", "fun"];

      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const errorBox = document.getElementById("form-error");
      const list = document.getElementById("expense-list");
      const total = document.getElementById("total");
      const filterCategory = document.getElementById("filter-category");
      const filterFrom = document.getElementById("filter-from");
      const filterTo = document.getElementById("filter-to");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (!Array.isArray(saved)) return [];
          return saved.filter(function (item) {
            return item &&
              typeof item.id === "string" &&
              typeof item.category === "string" &&
              typeof item.date === "string" &&
              Number.isFinite(Number(item.amount));
          });
        } catch (error) {
          return [];
        }
      }

      function saveExpenses() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      }

      function formatMoney(value) {
        return Number(value).toFixed(2);
      }

      function isVisible(expense) {
        const selectedCategory = filterCategory.value;
        const from = filterFrom.value;
        const to = filterTo.value;

        if (selectedCategory !== "all" && expense.category !== selectedCategory) return false;
        if (from && expense.date < from) return false;
        if (to && expense.date > to) return false;
        return true;
      }

      function render() {
        list.innerHTML = "";
        const visibleExpenses = expenses.filter(isVisible);
        let visibleTotal = 0;
        const categoryTotals = {
          groceries: 0,
          transport: 0,
          bills: 0,
          fun: 0
        };

        visibleExpenses.forEach(function (expense) {
          const amount = Number(expense.amount);
          visibleTotal += amount;
          if (Object.prototype.hasOwnProperty.call(categoryTotals, expense.category)) {
            categoryTotals[expense.category] += amount;
          }

          const row = document.createElement("div");
          row.className = "expense";
          row.dataset.id = expense.id;

          const amountElement = document.createElement("div");
          amountElement.className = "amount";
          amountElement.textContent = "$" + formatMoney(amount);

          const categoryElement = document.createElement("div");
          categoryElement.className = "category";
          categoryElement.textContent = expense.category;

          const dateElement = document.createElement("div");
          dateElement.className = "date";
          dateElement.textContent = expense.date;

          const deleteButton = document.createElement("button");
          deleteButton.className = "exp-del";
          deleteButton.type = "button";
          deleteButton.textContent = "Delete";
          deleteButton.setAttribute("aria-label", "Delete expense");

          row.append(amountElement, categoryElement, dateElement, deleteButton);

          if (expense.note) {
            const noteElement = document.createElement("div");
            noteElement.className = "note";
            noteElement.textContent = expense.note;
            row.appendChild(noteElement);
          }

          list.appendChild(row);
        });

        if (visibleExpenses.length === 0) {
          const empty = document.createElement("div");
          empty.className = "empty";
          empty.textContent = "No expenses match the current filters.";
          list.appendChild(empty);
        }

        total.textContent = formatMoney(visibleTotal);

        categories.forEach(function (category) {
          const element = document.querySelector('.cat-total[data-cat="' + category + '"]');
          element.innerHTML = category.charAt(0).toUpperCase() + category.slice(1) +
            "<strong>$" + formatMoney(categoryTotals[category]) + "</strong>";
        });
      }

      form.addEventListener("submit", function (event) {
        event.preventDefault();

        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const date = dateInput.value;

        if (rawAmount === "" || !Number.isFinite(amount) || amount <= 0 || !date) {
          errorBox.textContent = "Please enter a valid positive amount and select a date.";
          return;
        }

        errorBox.textContent = "";
        expenses.unshift({
          id: String(Date.now()) + "-" + Math.random().toString(36).slice(2),
          amount: amount,
          category: categoryInput.value,
          date: date,
          note: noteInput.value.trim()
        });

        saveExpenses();
        amountInput.value = "";
        noteInput.value = "";
        render();
        amountInput.focus();
      });

      list.addEventListener("click", function (event) {
        const button = event.target.closest(".exp-del");
        if (!button) return;

        const row = button.closest(".expense");
        if (!row) return;

        expenses = expenses.filter(function (expense) {
          return expense.id !== row.dataset.id;
        });

        saveExpenses();
        render();
      });

      [filterCategory, filterFrom, filterTo].forEach(function (filter) {
        filter.addEventListener("change", render);
        filter.addEventListener("input", render);
      });

      render();
    })();
  </script>
</body>
</html>
